// ❌ BAD - Logic dumped in constructor, no input, not reusable
export class ProductCard {
  product: Product;
  constructor() {
    this.product = { id: 1, name: 'Laptop', price: 999 }; // hardcoded
  }
}

// ✅ GOOD - Standalone component with @Input, reusable anywhere
import { Component, Input } from '@angular/core';
import { CurrencyPipe } from '@angular/common';

@Component({
  selector: 'product-card',
  standalone: true,
  imports: [CurrencyPipe],
  template: `
    <div class="card">
      <h2>{{ product.name }}</h2>
      <p>{{ product.price | currency }}</p>
    </div>
  `
})
export class ProductCardComponent {
  @Input({ required: true }) product!: Product;
}

// ❌ BAD - Two structural directives on one element causes a compile error
// <tr *ngFor="let order of orders" *ngIf="order.isPaid">...</tr>

// ✅ GOOD - ng-container for multiple directives + Angular 17 @if block
import { Component } from '@angular/core';
import { NgClass } from '@angular/common';

@Component({
  selector: 'order-list',
  standalone: true,
  imports: [NgClass],
  template: `
    @for (order of orders; track order.id) {
      @if (order.isPaid) {
        <tr [ngClass]="{ 'urgent': order.isLate }">
          <td>{{ order.reference }}</td>
        </tr>
      }
    }
  `
})
export class OrderListComponent {
  orders: Order[] = [];
}

