// ❌ BAD - HTTP call in constructor, no cleanup, ViewChild used too early
export class OrderDetailComponent {
  @ViewChild('chart') chart!: ElementRef; // undefined here
  constructor(private svc: OrderService) {
    this.orders = svc.getOrders().subscribe(); // leaks, no cleanup
  }
}

// ✅ GOOD - Correct hook usage with automatic cleanup
import { Component, OnInit, inject, DestroyRef } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

@Component({ selector: 'order-detail', standalone: true, template: '' })
export class OrderDetailComponent implements OnInit {
  private orderSvc = inject(OrderService);
  private destroyRef = inject(DestroyRef);
  orders: Order[] = [];

  ngOnInit() {
    this.orderSvc.getOrders()
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe(data => this.orders = data);
  }
}

