// The rf & 2 block only runs when a binding changed - not a full re-render
@Component({
  selector: 'product-list',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ul>@for (p of products; track p.id) { <li>{{ p.name }}</li> }</ul>`
})
export class ProductListComponent {
  products = input<Product[]>([]);
}

// ❌ BAD - Service instantiated manually, no DI, can't be mocked or reused
export class CheckoutComponent {
  private paymentSvc = new PaymentService(); // tight coupling, untestable
}

// ✅ GOOD - DI with hierarchical scoping
import { Injectable, Component, inject } from '@angular/core';

@Injectable({ providedIn: 'root' }) // app-wide singleton
export class PaymentService {
  processPayment(amount: number) { /* ... */ }
}

@Component({
  selector: 'checkout',
  standalone: true,
  template: `<button (click)="pay()">Pay Now</button>`
})
export class CheckoutComponent {
  private paymentSvc = inject(PaymentService); // DI resolves the singleton
  pay() { this.paymentSvc.processPayment(this.total); }
}

// ❌ BAD - Eager import: everything lands in main.js regardless of route visited
import { CheckoutComponent } from './checkout/checkout.component';
export const routes: Routes = [
  { path: 'checkout', component: CheckoutComponent } // always in the bundle
];

// ✅ GOOD - Lazy loading with loadComponent and loadChildren
import { Routes } from '@angular/router';
export const APP_ROUTES: Routes = [
  {
    path: 'checkout',
    loadComponent: () =>
      import('./checkout/checkout.component').then(m => m.CheckoutComponent)
  },
  {
    path: 'admin',
    loadChildren: () =>
      import('./admin/admin.routes').then(m => m.ADMIN_ROUTES)
  }
];

// ❌ BAD - NgModule approach: must declare component AND manage shared imports in a module
@NgModule({
  declarations: [InvoiceListComponent],
  imports: [CommonModule, RouterModule]
})
export class InvoiceModule {}

// ✅ GOOD - Standalone component owns its imports, no NgModule needed
import { Component } from '@angular/core';
import { RouterLink } from '@angular/router';
import { CurrencyPipe, DatePipe } from '@angular/common';

@Component({
  selector: 'invoice-list',
  standalone: true,
  imports: [RouterLink, CurrencyPipe, DatePipe],
  template: `
    @for (inv of invoices; track inv.id) {
      <a [routerLink]="['/invoices', inv.id]">{{ inv.total | currency }} - {{ inv.date | date }}</a>
    }
  `
})
export class InvoiceListComponent { invoices: Invoice[] = []; }

// ❌ BAD - Manual instantiation: untestable, no scoping, no DI benefits
export class InvoiceListComponent {
  private svc = new InvoiceService(); // hardcoded, impossible to mock in tests
}

// ✅ GOOD - DI via inject() with root singleton service
import { Injectable, Component, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';

@Injectable({ providedIn: 'root' })
export class InvoiceService {
  private http = inject(HttpClient);
  getInvoices() {
    return this.http.get<Invoice[]>('/api/invoices');
  }
}

@Component({ selector: 'invoice-list', standalone: true, template: '' })
export class InvoiceListComponent {
  private invoiceSvc = inject(InvoiceService);
  invoices$ = this.invoiceSvc.getInvoices();
}

