// ✅ GOOD - Clear smart/dumb separation
@Component({ selector: 'order-table', standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush, template: '' })
export class OrderTableComponent {
  orders = input.required<Order[]>();
  rowClick = output<Order>();
  onSelect(order: Order) { this.rowClick.emit(order); }
}

@Component({ selector: 'orders-page', standalone: true,
  imports: [OrderTableComponent],
  template: '<order-table [orders]="orders()" (rowClick)="onOrderSelected($event)" />'
})
export class OrdersPageComponent {
  private orderSvc = inject(OrderService);
  orders = toSignal(this.orderSvc.getOrders(), { initialValue: [] });
  onOrderSelected(order: Order) { /* navigate or open detail */ }
}

