// ✅ GOOD - Signal-based viewChild() - reactive, no lifecycle hook coupling
import { Component, viewChild, contentChild, ElementRef, AfterViewInit } from '@angular/core';

@Component({
  selector: 'chart-container',
  standalone: true,
  template: '<canvas #salesChart></canvas><ng-content />'
})
export class ChartContainerComponent implements AfterViewInit {
  canvas = viewChild<ElementRef>('salesChart');
  legend = contentChild('legendSlot');

  ngAfterViewInit() {
    console.log(this.canvas()?.nativeElement); // available here
  }
}
